"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[917689],{987580:e=>{e.exports=JSON.parse('{"tag":{"label":"fire","permalink":"/dst-api-webdocs/docs/tags/fire","allTagsPath":"/dst-api-webdocs/docs/tags","count":49,"items":[{"id":"game-scripts/prefabs/armor_dragonfly","title":"Armor Dragonfly","description":"Provides fire-resistant body armor with a chance to ignite attackers on successful block or parry.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_dragonfly"},{"id":"game-scripts/prefabs/birchnutdrake","title":"Birchnutdrake","description":"Prefab definition for the Birchnutdrake mob, a combat-capable monster withAI, looting, and fire-related mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/birchnutdrake"},{"id":"game-scripts/components/burnable","title":"Burnable","description":"Manages the burning and smoldering state of an entity, including fire effects, propagation, fuel consumption, and lifecycle hooks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/burnable"},{"id":"game-scripts/prefabs/burnable_locator_medium","title":"Burnable Locator Medium","description":"A non-physical, boat-anchored locator entity that triggers fire damage on its parent boat while smoldering or burning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/burnable_locator_medium"},{"id":"game-scripts/prefabs/candybag","title":"Candybag","description":"A wearable container item that functions as a backpack with fire-sensitive locking behavior and Ashdrop mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/candybag"},{"id":"game-scripts/prefabs/cave_banana_tree","title":"Cave Banana Tree","description":"Manages the full lifecycle of a cave banana tree, including growth, harvesting, chopping, burning, and regrowth into stumps or burnt stumps.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cave_banana_tree"},{"id":"game-scripts/prefabs/character_fire","title":"Character Fire","description":"A prefab component that creates a fire entity with variable heat output and animation levels for use on characters in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/character_fire"},{"id":"game-scripts/scenarios/chest_terrarium_fire","title":"Chest Terrarium Fire","description":"Triggers ignition of nearby evil flowers when the terrarium chest is opened.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_terrarium_fire"},{"id":"game-scripts/prefabs/coldfire","title":"Coldfire","description":"Manages the behavior and fuel dynamics of the cold fire structure, including burning, extinguishing, and fuel consumption modified by rain conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/coldfire"},{"id":"game-scripts/prefabs/coldfirefire","title":"Coldfirefire","description":"Creates a visual and thermal cold-fire effect entity that generates cooling heat rather than warming heat.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/coldfirefire"},{"id":"game-scripts/prefabs/cotl_tabernacle","title":"Cotl Tabernacle","description":"Manages the lifecycle, fueling, burning, and upgrade progression of the Cotl Tabernacle campfire entity across three tiers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cotl_tabernacle"},{"id":"game-scripts/prefabs/fireballstaff","title":"Fireballstaff","description":"A ranged weapon prefab that casts fireball projectiles with area-of-effect targeting and custom reticule logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fireballstaff"},{"id":"game-scripts/firelevel","title":"Firelevel","description":"Defines static configuration parameters for a fire-like entity\'s visual, thermal, and burning behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/firelevel"},{"id":"game-scripts/prefabs/firepen","title":"Firepen","description":"A ranged weapon that ignites targets, unfreezes frozen entities, wakes sleeping creatures, and fuels burnable objects using fire-based projectiles.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/firepen"},{"id":"game-scripts/prefabs/firepit","title":"Firepit","description":"A structure that provides a controllable fire source for cooking, heating, and light, fueled by consumable items and supporting charcoal production.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/firepit"},{"id":"game-scripts/prefabs/firesuppressor","title":"Firesuppressor","description":"Manages fire suppression operations, including fire detection, extinguishing, and fuel-dependent activation with emergency mode handling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/firesuppressor"},{"id":"game-scripts/prefabs/flower_evil","title":"Flower Evil","description":"A harvestable, sanity-affecting decorative flower that drops petals upon picking and can ignite wildfires.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flower_evil"},{"id":"game-scripts/prefabs/flower_withered","title":"Flower Withered","description":"A pickable, renewable grass source that provides cutgrass and can ignite wildfires.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flower_withered"},{"id":"game-scripts/prefabs/furniture_tables","title":"Furniture Tables","description":"Defines shared logic and prefab templates for wooden and stone tables, including decor handling, burning behavior, and hammer interaction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/furniture_tables"},{"id":"game-scripts/prefabs/homesign","title":"Homesign","description":"Creates a durable, hammerable signpost that can be written on and interacts with fire and loot-dropping mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/homesign"},{"id":"game-scripts/prefabs/lava_pond","title":"Lava Pond","description":"A large environmental hazard that emits heat, ignites nearby flammable objects on contact, propagates fire, and triggers music events when engaged by the Dragonfly boss.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lava_pond"},{"id":"game-scripts/prefabs/lavae","title":"Lavae","description":"A temporary hostile minion spawned by the Volcano that chases and attacks targets selected by its mother entity, with a fixed lifespan and fire immunity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavae"},{"id":"game-scripts/scenarios/lightonfire","title":"Lightonfire","description":"Triggers fire ignition on an entity upon creation by calling `Burnable:Ignite()` if the burnable component is present.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/lightonfire"},{"id":"game-scripts/prefabs/marsh_plant","title":"Marsh Plant","description":"Creates networked prefabs for marsh plants and pond algae, configuring visual state, burnable properties, and world propagation behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/marsh_plant"},{"id":"game-scripts/prefabs/mast_broken","title":"Mast Broken","description":"Represents a broken boat mast that can be repaired or burned, dropping loot and triggering visual/sound effects when interacted with.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mast_broken"},{"id":"game-scripts/prefabs/mermthrone","title":"Mermthrone","description":"Represents the Merm King\u2019s throne structure in DST, supporting construction phases, occupation by the Merm King, burning, and destruction with appropriate game events and loot behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mermthrone"},{"id":"game-scripts/prefabs/oceanvine","title":"Oceanvine","description":"Manages the behavior, harvesting, burning, and dynamic spawing of ocean vines in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanvine"},{"id":"game-scripts/prefabs/pigskin","title":"Pigskin","description":"A consumable meat item that can be stacked, burned, and traded for gold, belonging to the \\"horrible\\" food category.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigskin"},{"id":"game-scripts/prefabs/plant_normal","title":"Plant Normal","description":"Implements lifecycle and interaction logic for growing crops and their ground variants, including maturation, withering, harvesting, burning, and rotting behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/plant_normal"},{"id":"game-scripts/prefabs/portablefirepit","title":"Portablefirepit","description":"Manages the portable firepit item and its deployed state, handling fuel consumption, ignition, dismantling, and charcoal production logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/portablefirepit"},{"id":"game-scripts/components/propagator","title":"Propagator","description":"Manages heat propagation and thermal effects (e.g., fire melting, freezing relief, damage) between nearby entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/propagator"},{"id":"game-scripts/prefabs/rainometer","title":"Rainometer","description":"A structure component that tracks local rain levels via animation and responds to player interaction and environmental effects like fire.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rainometer"},{"id":"game-scripts/prefabs/rat_gym","title":"Rat Gym","description":"Manages carrat training sessions, item handling, and structural state changes for rat gyms in the Year of the Carrat event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rat_gym"},{"id":"game-scripts/prefabs/scarecrow","title":"Scarecrow","description":"A decorative and functional structure that can be built by players to occupy space and interact with dressing-up mechanics; it supports hammering, burning, and skin changes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/scarecrow"},{"id":"game-scripts/stategraphs/SGfiresuppressor","title":"Sgfiresuppressor","description":"Manages the state machine for the Fire Suppressor structure, handling its startup, idle, spinning, and extinguishing animations and sounds.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGfiresuppressor"},{"id":"game-scripts/stategraphs/SGfruitdragon","title":"Sgfruitdragon","description":"State graph for the Fruit Dragon entity that manages its idle, ripening, sleeping, and combat-related states including fire-based attacks and challenge duels.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGfruitdragon"},{"id":"game-scripts/stategraphs/SGstageusher","title":"Sgstageusher","description":"Defines the state machine for the Stageusher character, managing transitions between idle, sitting/standing, walking, attacking, and extinguishing states based on animation events and component interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGstageusher"},{"id":"game-scripts/prefabs/spicepack","title":"Spicepack","description":"A wearable backpack item that provides inventory storage, functions as a food preserver, and responds to fire ignition and extinguishing by locking/unlocking its contents.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spicepack"},{"id":"game-scripts/standardcomponents","title":"Standardcomponents","description":"A collection of utility functions for adding common physics, burnable, freezable, perishable, hauntable, and deployment behaviors to entities in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/standardcomponents"},{"id":"game-scripts/prefabs/stickheads","title":"Stickheads","description":"Creates and configures the Pig Head and Merm Head prefabs, which are destructible structures that produce specific loot, respond to fire, wake up on full moons, and can be haunted.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/stickheads"},{"id":"game-scripts/map/static_layouts/trap_firestaff","title":"Trap Firestaff","description":"Defines a static world map layout for a trap event that spawns a firestaff and multiple fire hounds.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/trap_firestaff"},{"id":"game-scripts/prefabs/wargshrine","title":"Wargshrine","description":"A structure that accepts torches to become active, enabling a prototyper and emitting flame; deactivates when extinguished or deconstructed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wargshrine"},{"id":"game-scripts/prefabs/waterprojectiles","title":"Waterprojectiles","description":"Defines prefabs and behaviors for water-based projectiles (snowballs, water balloons, ink splats, bile splats, and water streaks), each implementing custom collision handling, projectile physics, and fire suppression or status effects via the wateryprotection and complexprojectile components.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waterprojectiles"},{"id":"game-scripts/components/wildfires","title":"Wildfires","description":"Manages wildfire ignition mechanics based on environmental conditions and active players.","permalink":"/dst-api-webdocs/docs/game-scripts/components/wildfires"},{"id":"game-scripts/prefabs/willow","title":"Willow","description":"Willow is a player character prefab that specializes in fire-based mechanics, with abilities tied to burning entities, ember spawning on death, and resistance to temperature extremes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/willow"},{"id":"game-scripts/prefabs/yot_catcoonshrine","title":"Yot Catcoonshrine","description":"Acts as a special\u796d\u575b that holds a birdfeather offering and becomes a prototyper once activated; supports burning, hammering, and state persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yot_catcoonshrine"},{"id":"game-scripts/prefabs/yotc_carrat_race_start","title":"Yotc Carrat Race Start","description":"A structure that initiates and manages carrat racing events; it spawns racers, triggers race start/end logic, and handles destruction with burn and hammer interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotc_carrat_race_start"},{"id":"game-scripts/prefabs/yotd_dragonshrine","title":"Yotd Dragonshrine","description":"A ritual shrine that accepts charcoal offerings, activates a prototyper when offered, and resets to an empty trader state when used or extinguished.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotd_dragonshrine"},{"id":"game-scripts/prefabs/yotr_decor","title":"Yotr Decor","description":"Creates decorative campfire-like structures that burn fuel, produce light, and interact with weather and gameplay events.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotr_decor"}],"unlisted":false}}')}}]);